$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR_NUMBER = 18
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0
$FINDINGS = $null

Write-Host "Polling for Copilot code review agent findings..."

while ($ELAPSED -lt $TIMEOUT) {
    # Strategy A
    $reviewsA = gh api "/repos/$REPO/pulls/$PR_NUMBER/reviews" --jq '.[] | select(.body | test("Copilot.s findings")) | {id: .id, body: .body}' 2>$null
    if ($reviewsA) { $FINDINGS = $reviewsA; break }

    # Strategy B
    $reviewsB = gh api "/repos/$REPO/pulls/$PR_NUMBER/reviews" --jq '.[] | select(.body | test("Pull request overview")) | {id: .id, body: .body}' 2>$null
    if ($reviewsB) { $FINDINGS = $reviewsB; break }

    # Strategy C
    $reviewsC = gh api "/repos/$REPO/pulls/$PR_NUMBER/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | {id: .id, body: .body}' 2>$null
    if ($reviewsC) { $FINDINGS = $reviewsC; break }

    # Strategy D
    $reviewsD = gh api "/repos/$REPO/pulls/$PR_NUMBER/comments" --jq '.[] | select(.user.login == "Copilot") | {id: .id, body: .body}' 2>$null
    if ($reviewsD) { $FINDINGS = $reviewsD; break }

    Write-Host "  [$ELAPSED s] No findings yet, waiting $INTERVAL s..."
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($FINDINGS) {
    Write-Host "Found Copilot review!"
    Write-Host $FINDINGS
} else {
    Write-Host "TIMEOUT: Copilot review agent did not post within $TIMEOUT seconds."
}

